```go
// computeSortFieldsWithNamespace returns sortFields with partition key prepended if namespace is enabled
func computeSortFieldsWithNamespace(schema *schemapb.CollectionSchema, namespaceEnabled bool, primaryKeyFieldID int64) []int64 {
	sortFields := []int64{primaryKeyFieldID}
	if namespaceEnabled {
		if partitionKey, err := typeutil.GetPartitionKeyFieldSchema(schema); err == nil && partitionKey != nil {
			sortFields = append([]int64{partitionKey.GetFieldID()}, sortFields...)
		}
	}
	return sortFields
}
```

